import { generateText } from 'ai';
import { createTavilyClient } from './tools/tavily';

const tavily = createTavilyClient();

export async function researchAgent(query: string) {
  const { text } = await generateText({
    model: 'openai/gpt-4o',
    prompt: `Research this topic thoroughly: ${query}. Use web search and cite sources.`,
    tools: {
      search: {
        description: 'Search the web for recent information',
        parameters: z.object({
          query: z.string().describe('search query'),
        }),
        execute: async ({ query }) => {
          const results = await tavily.search(query);
          return {
            sources: results.results,
            summary: results.answer
          };
        },
      },
    },
  });
  return text;
}

import { useChat } from 'ai/react';

export function ResearchChat() {
  const { messages, input, handleInputChange, handleSubmit, isLoading } = useChat({
    api: '/api/research',
    initialMessages: [
      {
        role: 'assistant',
        content: 'Ask me to research any topic!',
      },
    ],
  });

  return (
    <div className="research-chat">
      {messages.map((m) => (
        <div key={m.id}>{m.content}</div>
      ))}
      <form onSubmit={handleSubmit}>
        <input
          value={input}
          onChange={handleInputChange}
          placeholder="Research: latest AI regulations"
        />
      </form>
    </div>
  );
}

import { generateObject } from 'ai';
import { z } from 'zod';

const ResearchReportSchema = z.object({
  summary: z.string(),
  key_findings: z.array(z.string()),
  sources: z.array(z.object({
    title: z.string(),
    url: z.string(),
    recency: z.string(),
  })),
});

export async function synthesizeResearch(query: string) {
  const { object } = await generateObject({
    model: 'anthropic/claude-3-5-sonnet-20240620',
    schema: ResearchReportSchema,
    prompt: `Conduct thorough research on: ${query}. Verify source recency and credibility.`,
    tools: { /* search tools */ },
  });
  return object;
}

import { createStreamableValue } from 'ai/rsc';
import { NextRequest } from 'next/server';

export const runtime = 'edge';

export async function POST(req: NextRequest) {
  const { prompt } = await req.json();

  const stream = createStreamableValue();

  (async () => {
    const result = await researchAgent(prompt);
    stream.update(result);
    stream.done();
  })();

  return stream.value;
}

